#include <stdio.h>
#include <stdlib.h>

int *alociraj_niz(int broj_el) {
    int *pok = (int*)malloc(sizeof(int) * broj_el);
    return pok;
}

void oslobodi_niz(int *niz) {
    free(niz);
}

int main() {
    int n = 0;

    printf("Unesite broj elemenata niza: ");
    scanf("%d", &n);

    int *niz = alociraj_niz(n);

    if (!niz) { /* kao i: if (niz == NULL) */
        printf("Alokacija nije uspjela!\n");
        return 1;
    }

    printf("Unesite elemente niza:\n");
    int a = 0;
    for (a = 0; a < n; a++) {
        printf("niz[%i] = ", a);
        scanf("%i", &niz[a]);
    }

    printf("Uneseni niz naopako ispisan:\n");
    for (a = n - 1; a >= 0; a--) {
        printf("%i ", niz[a]);
    }
    printf("\n");

    /* moramo osloboditi zauzetu memoriju */
    oslobodi_niz(niz);

    return 0;
}
